module ring_counter_8bit (count, rst_clk, reset, en);
   input rst_clk, reset, en;
   output [7:0] count;

   reg [7:0] count;

   always @(posedge rst_clk or posedge reset) begin
      if (reset)
         count <= 8'b0000_0001;
      else if (en)
         count <= {count[6:0], count[7]};
   end

endmodule
